'use client';import { useState, useEffect, useCallback, useRef } from 'react';import { useRouter } from 'next/navigation';import { useAuthStore } from '@/lib/stores/authStore';import api from '@/src/lib/api';import { motion, AnimatePresence } from 'framer-motion';import toast, { Toaster } from 'react-hot-toast';import {    BookOpen, Search, Shuffle, Bookmark, Zap, Focus, Target, RefreshCw, PenLine, Sparkles, Clock, X, Check, ChevronDown, CheckCircle2, AlertCircle, ScanText, History, UploadCloud} from 'lucide-react';import {    Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, LineChart, Line, XAxis, YAxis, Tooltip as RechartsTooltip} from 'recharts';const { apiClient, getServiceUrl } = api;interface QuestionItem {    id: string;    text: string;    category: string;    difficulty: 'easy' | 'medium' | 'hard';    tags: string[];    score?: number;    bookmarked?: boolean;    answerDraft?: string;    isGenerating?: boolean;    isEvaluating?: boolean;}interface EvaluationResult {    scores: {        clarity: number;        relevance: number;        structure: number;        confidence: number;        depth: number;    };    star_detected: {        situation: boolean;        task: boolean;        action: boolean;        result: boolean;    };    tone: string;     hedging_words_found: string[];    improvement_tips: string[];    improved_answer: string;    overall_score: number;}interface PrepRound {    title: string;    description: string;    questions: QuestionItem[];}interface JdAnalysis {    matched_skills: string[];    missing_skills: string[];    culture_signals: string[];    keyword_gaps: string[];    interview_rounds: PrepRound[];}interface AnswerHistory {    id: string;    created_at: string;    overall_score: number;    answer_text: string;    scores_json: any;}const CATEGORIES = [    { id: 'behavioral', label: 'Behavioral' },    { id: 'technical', label: 'Technical' },    { id: 'situational', label: 'Situational' },    { id: 'culture_fit', label: 'Culture Fit' },    { id: 'leadership', label: 'Leadership' },    { id: 'problem_solving', label: 'Problem Solving' },];const ROLES = ['SDE Intern', 'Frontend', 'Backend', 'Full Stack', 'PM', 'Data Analyst'];const PRACTICE_TYPES = ['System Design', 'Technical Coding', 'Behavioral', 'Communication', 'Leadership', 'Values & Culture'];const STARTER_QUESTIONS: QuestionItem[] = [    { id: '1', text: 'Tell me about yourself.', category: 'behavioral', difficulty: 'easy', tags: ['intro', 'self_awareness'] },    { id: '2', text: 'Why do you want to work here?', category: 'culture_fit', difficulty: 'easy', tags: ['motivation'] },    { id: '3', text: 'Describe a time you failed and what you learned.', category: 'behavioral', difficulty: 'medium', tags: ['failure', 'growth'] },    { id: '4', text: 'How do you handle disagreements with teammates?', category: 'situational', difficulty: 'medium', tags: ['conflict'] },    { id: '5', text: 'Walk me through a project you led from start to finish.', category: 'leadership', difficulty: 'medium', tags: ['leadership'] },    { id: '6', text: 'How would you design a URL shortener?', category: 'technical', difficulty: 'hard', tags: ['system_design'] },    { id: '7', text: 'Tell me about a time you had to learn something quickly under pressure.', category: 'behavioral', difficulty: 'medium', tags: ['learning'] },    { id: '8', text: 'Describe your approach to prioritizing multiple urgent tasks.', category: 'situational', difficulty: 'medium', tags: ['prioritization'] },];const ProgressRing = ({ value, max }: { value: number; max: number }) => {    const radius = 16;    const circumference = 2 * Math.PI * radius;    const offset = circumference - (value / max) * circumference;    return (        <div className="relative w-10 h-10 flex items-center justify-center">            <svg className="w-full h-full -rotate-90" viewBox="0 0 40 40">                <circle cx="20" cy="20" r={radius} fill="none" stroke="rgba(255,255,255,0.1)" strokeWidth="3" />                <circle cx="20" cy="20" r={radius} fill="none" stroke="#7c3aed" strokeWidth="3" strokeLinecap="round"                    strokeDasharray={circumference} strokeDashoffset={offset} className="transition-all duration-500" />            </svg>            <span className="absolute text-[10px] font-bold text-[var(--text-primary)]">{value}</span>        </div>    );};export default function PrepHubPage() {    const router = useRouter();    const { isAuthenticated, isLoading: authLoading } = useAuthStore();    const [questions, setQuestions] = useState<QuestionItem[]>(STARTER_QUESTIONS);    const [activeQuestionId, setActiveQuestionId] = useState<string | null>(null);    const [elapsedSeconds, setElapsedSeconds] = useState(0);    const [isTimerActive, setIsTimerActive] = useState(false);    const [selectedRole, setSelectedRole] = useState<string>('SDE Intern');    const [selectedCategory, setSelectedCategory] = useState<string | null>(null);    const [selectedDifficulty, setSelectedDifficulty] = useState<string | null>(null);    const [showJDInput, setShowJDInput] = useState(false);    const [jdContext, setJdContext] = useState('');    const [resumeContext, setResumeContext] = useState('');    const [jdAnalysis, setJdAnalysis] = useState<JdAnalysis | null>(null);    const [isAnalyzingJd, setIsAnalyzingJd] = useState(false);    const [activeRoundIndex, setActiveRoundIndex] = useState<number | null>(null);    const [selectedPracticeTypes, setSelectedPracticeTypes] = useState<string[]>([]);    const [uploadMode, setUploadMode] = useState<'text' | 'file'>('text');    const [uploadingResume, setUploadingResume] = useState(false);    const [answerText, setAnswerText] = useState('');    const [showStarHelper, setShowStarHelper] = useState(false);    const [isGenerating, setIsGenerating] = useState(false);    const [isEvaluating, setIsEvaluating] = useState(false);    const [showHistory, setShowHistory] = useState(false);    const [answerHistory, setAnswerHistory] = useState<AnswerHistory[]>([]);    const [isLoadingHistory, setIsLoadingHistory] = useState(false);    const textareaRef = useRef<HTMLTextAreaElement>(null);    // ── Right Panel (AI Coach) ──    const [evalResult, setEvalResult] = useState<EvaluationResult | null>(null);    const [showImprovedAnswer, setShowImprovedAnswer] = useState(false);    // Timer Effect    useEffect(() => {        let interval: NodeJS.Timeout;        if (isTimerActive) {            interval = setInterval(() => setElapsedSeconds(s => s + 1), 1000);        }        return () => clearInterval(interval);    }, [isTimerActive]);    // Format timer    const formatTime = (totalSeconds: number) => {        const m = Math.floor(totalSeconds / 60);        const s = totalSeconds % 60;        return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;    };    // Auto-resize textarea    useEffect(() => {        if (textareaRef.current) {            textareaRef.current.style.height = 'auto';            textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;        }    }, [answerText]);    const handleSelectQuestion = (qId: string) => {        if (activeQuestionId) {            setQuestions(prev => prev.map(q => q.id === activeQuestionId ? { ...q, answerDraft: answerText } : q));        }        const newQ = questions.find(q => q.id === qId);        setActiveQuestionId(qId);        setAnswerText(newQ?.answerDraft || '');        setEvalResult(null); // Reset evaluation for new question        setShowImprovedAnswer(false);        setAnswerHistory([]); // Clear history for new question        if (!isTimerActive) setIsTimerActive(true);    };    // Fetch History    useEffect(() => {        if (showHistory && activeQuestionId && answerHistory.length === 0) {            const fetchHistory = async () => {                setIsLoadingHistory(true);                try {                    const res = await apiClient.get(`${getServiceUrl('resume')}/prep/history/${encodeURIComponent(activeQuestionId)}`);                    setAnswerHistory(res.data.history || []);                } catch (e) {                    console.error("Failed to fetch history", e);                } finally {                    setIsLoadingHistory(false);                }            };            fetchHistory();        }    }, [showHistory, activeQuestionId, answerHistory.length]);    // Surprise Me    const handleSurpriseMe = () => {        const randomQ = questions[Math.floor(Math.random() * questions.length)];        handleSelectQuestion(randomQ.id);    };    // Toggle Bookmark    const toggleBookmark = (e: React.MouseEvent, qId: string) => {        e.stopPropagation();        setQuestions(prev => prev.map(q => q.id === qId ? { ...q, bookmarked: !q.bookmarked } : q));    };    const handleGenerateAnswer = async () => {        if (!activeQuestion) return;        setIsGenerating(true);        try {            const res = await apiClient.post(`${getServiceUrl('resume')}/prep/generate-draft`, {                question: activeQuestion.text,                job_description: jdContext || null,                resume_summary: resumeContext || null,            });            setAnswerText(res.data.draft_text);            toast.success("Draft generated!");        } catch (error) {            toast.error("Failed to generate draft. Please try again.");            console.error(error);        } finally {            setIsGenerating(false);        }    };    const handleEvaluateAnswer = async () => {        if (!activeQuestion || !answerText.trim()) return;        setIsEvaluating(true);        try {            const res = await apiClient.post(`${getServiceUrl('resume')}/prep/evaluate-answer`, {                question: activeQuestion.text,                answer: answerText,                job_description: jdContext || null,            });            setEvalResult(res.data);            setQuestions(prev => prev.map(q => q.id === activeQuestionId ? { ...q, score: res.data.overall_score } : q));            toast.success("Evaluation complete!");        } catch (error) {            toast.error("Evaluation failed. Please try again.");            console.error(error);        } finally {            setIsEvaluating(false);        }    };    const handleAnalyzeJD = async () => {        if (!jdContext.trim()) return;        setIsAnalyzingJd(true);        try {            const res = await apiClient.post(`${getServiceUrl('resume')}/prep/analyze-jd`, {                job_description: jdContext,                resume_summary: resumeContext || null,                practice_types: selectedPracticeTypes.length > 0 ? selectedPracticeTypes : null            });            const analysisData: JdAnalysis = res.data;            setJdAnalysis(analysisData);            if (analysisData.interview_rounds && analysisData.interview_rounds.length > 0) {                const allGeneratedQuestions: QuestionItem[] = [];                analysisData.interview_rounds.forEach(round => {                    if (round.questions) {                        allGeneratedQuestions.push(...round.questions.map(q => ({                            ...q,                            category: q.category.toLowerCase(),                            difficulty: (q.difficulty.toLowerCase() as 'easy' | 'medium' | 'hard') || 'medium'                        })));                    }                });                if (allGeneratedQuestions.length > 0) {                    setQuestions(allGeneratedQuestions);                    setActiveRoundIndex(0);                 }            }            toast.success("JD Analyzed successfully!");        } catch (error) {            toast.error("Failed to analyze JD");            console.error(error);        } finally {            setIsAnalyzingJd(false);        }    };    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {        const file = e.target.files?.[0];        if (!file) return;        if (file.type !== 'application/pdf') {            toast.error("Please upload a PDF file.");            return;        }        setUploadingResume(true);        const formData = new FormData();        formData.append("file", file);        try {            const res = await apiClient.post(`${getServiceUrl('session')}/sessions/upload-resume`, formData, {                headers: { 'Content-Type': 'multipart/form-data' }            });            setResumeContext(res.data.resume_text || '');            setUploadMode('text');             toast.success("Resume parsed successfully!");        } catch (error) {            console.error(error);            toast.error("Failed to parse resume.");        } finally {            setUploadingResume(false);            if (e.target) e.target.value = '';        }    };    const handleExportPlaybook = () => {        const answeredQuestions = questions.filter(q => q.answerDraft || (q.id === activeQuestionId && answerText));        if (answeredQuestions.length === 0) {            toast.error("You need to draft at least one answer to export a playbook!");            return;        }        const printWindow = window.open('', '_blank');        if (!printWindow) return;        let html = `            <html>            <head>                <title>Interview Playbook</title>                <style>                    body { font-family: system-ui, -apple-system, sans-serif; line-height: 1.6; max-width: 800px; margin: 0 auto; padding: 40px; color: #333; }                    h1 { color: #111; border-bottom: 2px solid #eee; padding-bottom: 10px; margin-bottom: 5px; }                    .subtitle { color: #64748b; font-size: 14px; margin-bottom: 30px; }                    .question { margin-top: 30px; page-break-inside: avoid; }                    .q-text { font-size: 18px; font-weight: bold; color: #6d28d9; margin-bottom: 10px; }                    .a-text { background: #f8fafc; padding: 15px; border-left: 4px solid #6d28d9; border-radius: 0 4px 4px 0; white-space: pre-wrap; }                    .meta { font-size: 12px; color: #64748b; margin-bottom: 5px; text-transform: uppercase; font-weight: bold; spacing: 1px; }                </style>            </head>            <body>                <h1>My Interview Playbook</h1>                <div class="subtitle">Generated by SynthHire AI Prep Hub</div>        `;        answeredQuestions.forEach((q, i) => {            const answer = q.id === activeQuestionId ? answerText : q.answerDraft;            html += `                <div class="question">                    <div class="meta">${q.category.replace('_', ' ')} • ${q.difficulty}</div>                    <div class="q-text">Q${i + 1}: ${q.text}</div>                    <div class="a-text">${answer}</div>                </div>             `;        });        html += '</body></html>';        printWindow.document.write(html);        printWindow.document.close();        setTimeout(() => printWindow.print(), 250);    };    const activeQuestion = questions.find(q => q.id === activeQuestionId);    const practicedCount = questions.filter(q => q.score !== undefined).length;    const filteredQuestions = questions        .filter(q => (!selectedCategory || q.category === selectedCategory) && (!selectedDifficulty || q.difficulty === selectedDifficulty))        .sort((a, b) => (b.bookmarked ? 1 : 0) - (a.bookmarked ? 1 : 0));     const getDifficultyColor = (d: string) => {        if (d === 'easy') return 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20 shadow-[0_0_10px_rgba(16,185,129,0.1)]';        if (d === 'medium') return 'text-yellow-400 bg-yellow-500/10 border-yellow-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]';        return 'text-red-400 bg-red-500/10 border-red-500/20 shadow-[0_0_10px_rgba(239,68,68,0.1)]';    };    const radarData = evalResult ? [        { subject: 'Clarity', A: evalResult.scores.clarity * 10, fullMark: 100 },        { subject: 'Relevance', A: evalResult.scores.relevance * 10, fullMark: 100 },        { subject: 'Structure', A: evalResult.scores.structure * 10, fullMark: 100 },        { subject: 'Confidence', A: evalResult.scores.confidence * 10, fullMark: 100 },        { subject: 'Depth', A: evalResult.scores.depth * 10, fullMark: 100 },    ] : [        { subject: 'Clarity', A: 0, fullMark: 100 },        { subject: 'Relevance', A: 0, fullMark: 100 },        { subject: 'Structure', A: 0, fullMark: 100 },        { subject: 'Confidence', A: 0, fullMark: 100 },        { subject: 'Depth', A: 0, fullMark: 100 },    ];    if (authLoading) return <div className="min-h-[calc(100vh-64px)] bg-[#0d0f1a] flex items-center justify-center"><div className="animate-spin w-10 h-10 border-4 border-violet-500 rounded-full border-t-transparent" /></div>;    const renderQuestionCard = (q: QuestionItem) => {        const isActive = activeQuestionId === q.id;        return (            <button                key={q.id}                onClick={() => handleSelectQuestion(q.id)}                className={`w-full text-left p-3 rounded-xl transition-all relative group flex items-start gap-3 border ${isActive ? 'bg-violet-500/10 border-violet-500/30' : 'bg-transparent border-transparent hover:bg-white/5'}`}            >                {isActive && <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-8 bg-violet-500 rounded-r-full shadow-[0_0_10px_#7c3aed]" />}                <div className="flex-1 min-w-0 pr-6">                    <p className={`text-xs leading-snug truncate ${isActive ? 'text-[var(--text-primary)] font-medium' : 'text-[var(--text-secondary)]'}`}>{q.text}</p>                    <div className="flex items-center gap-2 mt-2">                        <span className={`px-1.5 py-0.5 text-[9px] uppercase font-bold rounded border ${getDifficultyColor(q.difficulty)}`}>{q.difficulty}</span>                        {q.score !== undefined && (                            <span className="px-1.5 py-0.5 text-[9px] rounded bg-white/5 text-[var(--text-primary)] border border-white/10">{q.score} pts</span>                        )}                    </div>                </div>                <div className="flex flex-col items-center gap-2">                    <Bookmark                        onClick={(e) => toggleBookmark(e, q.id)}                        className={`w-3.5 h-3.5 transition-colors ${q.bookmarked ? 'text-yellow-400 fill-yellow-400' : 'text-slate-600 opacity-0 group-hover:opacity-100 hover:text-[var(--text-primary)]'}`}                    />                </div>            </button>        );    };    return (        <div className="h-[calc(100vh-64px)] font-sans flex flex-col overflow-hidden">            <Toaster position="top-right" toastOptions={{ style: { background: 'var(--card-bg)', color: 'var(--text-primary)', border: '1px solid var(--card-border)' } }} />            {}            <header className="h-16 flex-shrink-0 border-b border-[var(--card-border)] bg-[var(--card-bg)] flex items-center justify-between px-6">                <div className="flex items-center gap-3">                    <BookOpen className="text-violet-500 w-6 h-6" />                    <h1 className="text-xl font-bold text-[var(--text-primary)] tracking-wide">Prep Hub</h1>                </div>                <div className="flex items-center gap-6">                    <div className="flex items-center gap-3">                        <span className="text-xs text-[var(--text-secondary)] uppercase tracking-widest">{practicedCount} / {questions.length} practiced</span>                        <ProgressRing value={practicedCount} max={questions.length} />                    </div>                    <div className="flex items-center gap-2 text-sm font-medium text-[var(--text-secondary)] bg-[var(--card-bg)] px-3 py-1.5 rounded-lg border border-[var(--card-border)]">                        <Clock className="w-4 h-4 text-violet-400" />                        <span className="w-12 text-center">{formatTime(elapsedSeconds)}</span>                    </div>                </div>            </header>            {}            <main className="flex-1 flex overflow-hidden">                {}                <aside className="w-[300px] flex-shrink-0 border-r border-[var(--card-border)] bg-[var(--card-bg)] flex flex-col overflow-hidden">                    <div className="p-4 border-b border-[var(--card-border)] space-y-4 overflow-y-auto no-scrollbar flex-shrink-0 max-h-[50vh]">                        {}                        <button onClick={() => setShowJDInput(!showJDInput)} className="w-full flex items-center justify-center gap-2 py-2 bg-white/5 hover:bg-white/10 text-xs font-semibold text-[var(--text-primary)] rounded-lg transition-colors border border-white/5">                            {showJDInput ? 'Hide Job Description' : 'Add Target Job Description'}                        </button>                        <AnimatePresence>                            {showJDInput && (                                <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="space-y-3">                                    <textarea                                        value={jdContext} onChange={e => setJdContext(e.target.value)}                                        className="w-full h-24 bg-[#0A0D14] border border-white/5 rounded-lg p-3 text-xs text-[var(--text-primary)] resize-none focus:outline-none focus:border-violet-500/50 transition-colors"                                        placeholder="Paste full Job Description here..."                                    />                                    <div>                                        <div className="flex items-center gap-2 mb-2">                                            <span className="text-[10px] uppercase font-bold text-[var(--text-secondary)]">Provide Resume</span>                                            <div className="flex bg-white/5 p-0.5 rounded-md">                                                <button onClick={() => setUploadMode('text')} className={`px-2 py-0.5 text-[10px] rounded ${uploadMode === 'text' ? 'bg-white/10 text-[var(--text-primary)] shadow-sm' : 'text-[var(--text-secondary)] hover:text-[var(--text-primary)]'}`}>Text</button>                                                <button onClick={() => setUploadMode('file')} className={`px-2 py-0.5 text-[10px] rounded ${uploadMode === 'file' ? 'bg-white/10 text-[var(--text-primary)] shadow-sm' : 'text-[var(--text-secondary)] hover:text-[var(--text-primary)]'}`}>PDF File</button>                                            </div>                                        </div>                                        {uploadMode === 'text' ? (                                            <textarea                                                value={resumeContext} onChange={e => setResumeContext(e.target.value)}                                                className="w-full h-20 bg-[#0A0D14] border border-white/5 rounded-lg p-3 text-xs text-[var(--text-primary)] resize-none focus:outline-none focus:border-emerald-500/50 transition-colors"                                                placeholder="Paste Resume summary here..."                                            />                                        ) : (                                            <div className="relative w-full h-20 bg-[#0A0D14] border border-dashed border-emerald-500/30 rounded-lg flex flex-col items-center justify-center text-xs text-[var(--text-secondary)] hover:border-emerald-500/60 hover:bg-emerald-500/5 transition-all">                                                {uploadingResume ? (                                                    <div className="flex items-center gap-2 text-emerald-400"><RefreshCw className="w-4 h-4 animate-spin" /> Parsing PDF...</div>                                                ) : (                                                    <div className="flex flex-col items-center pointer-events-none">                                                        <UploadCloud className="w-5 h-5 mb-1 text-emerald-400" />                                                        <span>Click to upload PDF resume</span>                                                    </div>                                                )}                                                <input type="file" accept=".pdf" disabled={uploadingResume} onChange={handleFileUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />                                            </div>                                        )}                                    </div>                                    <div>                                        <span className="text-[10px] uppercase font-bold text-[var(--text-secondary)] mb-2 block">Practice Focus (Optional)</span>                                        <div className="flex flex-wrap gap-1.5">                                            {PRACTICE_TYPES.map(type => {                                                const isSelected = selectedPracticeTypes.includes(type);                                                return (                                                    <button                                                        key={type}                                                        onClick={() => setSelectedPracticeTypes(prev => isSelected ? prev.filter(t => t !== type) : [...prev, type])}                                                        className={`px-2 py-1 text-[10px] rounded-md transition-colors border ${isSelected ? 'bg-cyan-500/20 text-cyan-400 border-cyan-500/30' : 'bg-white/5 text-[var(--text-secondary)] border-white/5 hover:bg-white/10'}`}                                                    >                                                        {type}                                                    </button>                                                )                                            })}                                        </div>                                    </div>                                    <button onClick={handleAnalyzeJD} disabled={isAnalyzingJd || !jdContext} className="w-full py-2 bg-violet-600/20 text-violet-400 text-xs font-bold uppercase tracking-wider rounded-lg hover:bg-violet-600/30 transition-all border border-violet-500/30 flex items-center justify-center gap-2 shadow-[0_0_15px_rgba(124,58,237,0.1)]">                                        {isAnalyzingJd ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />} GENERATE TARGETED ROUNDS                                    </button>                                    {}                                    {jdAnalysis && (                                        <div className="bg-[#0A0D14] rounded-lg p-3 border border-white/5 text-[10px] space-y-2">                                            <div className="flex flex-wrap gap-1">                                                {jdAnalysis.matched_skills.map(s => <span key={s} className="px-1.5 py-0.5 rounded bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 flex items-center gap-1"><Check className="w-3 h-3" />{s}</span>)}                                                {jdAnalysis.missing_skills.map(s => <span key={s} className="px-1.5 py-0.5 rounded bg-red-500/10 text-red-400 border border-red-500/20 flex items-center gap-1"><X className="w-3 h-3" />{s}</span>)}                                            </div>                                            <div className="flex flex-wrap gap-1 pt-1 border-t border-white/5">                                                {jdAnalysis.culture_signals.map(s => <span key={s} className="px-1.5 py-0.5 rounded bg-white/5 text-[var(--text-secondary)]">{s}</span>)}                                            </div>                                        </div>                                    )}                                </motion.div>                            )}                        </AnimatePresence>                        {}                        <div className="flex items-center gap-2">                            <select value={selectedRole} onChange={e => setSelectedRole(e.target.value)} className="flex-1 bg-white/5 border border-white/10 rounded-lg px-2 py-1.5 text-xs text-[var(--text-primary)] focus:outline-none">                                {ROLES.map(r => <option key={r} value={r} className="bg-[#0A0D14]">{r}</option>)}                            </select>                            <button onClick={handleSurpriseMe} className="px-3 py-1.5 bg-cyan-500/10 text-cyan-400 border border-cyan-500/20 rounded-lg hover:bg-cyan-500/20 transition-colors flex items-center justify-center pointer" title="Surprise Me">                                <Shuffle className="w-4 h-4" />                            </button>                        </div>                        <div className="flex gap-1 overflow-x-auto no-scrollbar pb-1">                            {['easy', 'medium', 'hard'].map(d => (                                <button key={d} onClick={() => setSelectedDifficulty(d === selectedDifficulty ? null : d)} className={`px-2 py-1 text-[10px] uppercase font-bold tracking-wider rounded border ${selectedDifficulty === d ? getDifficultyColor(d) : 'border-white/5 bg-white/5 text-[var(--text-muted)] hover:text-[var(--text-primary)]'}`}>                                    {d}                                </button>                            ))}                        </div>                    </div>                    {}                    <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-2">                        {jdAnalysis?.interview_rounds && jdAnalysis.interview_rounds.length > 0 ? (                            jdAnalysis.interview_rounds.map((round, rIdx) => {                                const visibleQuestions = round.questions.filter(q => !selectedDifficulty || q.difficulty === selectedDifficulty);                                if (visibleQuestions.length === 0) return null;                                 const isExpanded = activeRoundIndex === rIdx;                                return (                                    <div key={rIdx} className="bg-[#0A0D14] rounded-xl border border-white/5 overflow-hidden">                                        <button                                            onClick={() => setActiveRoundIndex(isExpanded ? null : rIdx)}                                            className="w-full flex items-center justify-between p-3 bg-white/5 hover:bg-white/10 transition-colors"                                        >                                            <div className="flex flex-col items-start truncate pr-2">                                                <span className="text-xs font-bold tracking-wide text-violet-300 truncate">{round.title}</span>                                                <span className="text-[10px] text-[var(--text-muted)] truncate">{visibleQuestions.length} questions</span>                                            </div>                                            <ChevronDown className={`w-4 h-4 text-[var(--text-secondary)] transition-transform ${isExpanded ? 'rotate-180' : ''}`} />                                        </button>                                        <AnimatePresence>                                            {isExpanded && (                                                <motion.div initial={{ height: 0 }} animate={{ height: 'auto' }} exit={{ height: 0 }} className="overflow-hidden">                                                    <div className="p-2 space-y-1 bg-black/20">                                                        {visibleQuestions.map(q => {                                                            const syncedQ = questions.find(sq => sq.id === q.id) || q;                                                            return renderQuestionCard(syncedQ);                                                        })}                                                    </div>                                                </motion.div>                                            )}                                        </AnimatePresence>                                    </div>                                );                            })                        ) : (                            <div className="space-y-1">                                {filteredQuestions.map(q => renderQuestionCard(q))}                            </div>                        )}                    </div>                </aside>                {}                <div className="flex-1 flex flex-col relative overflow-hidden bg-[#0A0D14]">                    {activeQuestion ? (                        <>                            <div className="p-8 max-w-3xl mx-auto w-full flex-1 overflow-y-auto custom-scrollbar flex flex-col">                                {}                                <div className="mb-6 flex items-center justify-between">                                    <div className="flex gap-2">                                        <span className={`px-2 py-1 text-xs rounded-full border ${getDifficultyColor(activeQuestion.difficulty)}`}>{activeQuestion.difficulty}</span>                                        <span className="px-2 py-1 text-xs rounded-full bg-white/5 text-[var(--text-primary)] border border-white/5 uppercase tracking-wide">{activeQuestion.category.replace('_', ' ')}</span>                                    </div>                                </div>                                <h2 className="text-2xl font-bold text-[var(--text-primary)] mb-8 leading-relaxed">                                    {activeQuestion.text}                                </h2>                                {}                                <div className="flex-1 flex flex-col relative">                                    {}                                    <div className="flex justify-between items-center mb-2">                                        <button onClick={() => setShowStarHelper(!showStarHelper)} className={`text-xs flex items-center gap-1 font-medium transition-colors ${showStarHelper ? 'text-cyan-400' : 'text-[var(--text-muted)] hover:text-[var(--text-primary)]'}`}>                                            <Sparkles className="w-3 h-3" /> STAR Helper {showStarHelper ? 'On' : 'Off'}                                        </button>                                    </div>                                    {}                                    <div className={`flex flex-col gap-2 mb-3 overflow-hidden transition-all duration-300 ${showStarHelper ? 'h-auto opacity-100' : 'h-0 opacity-0'}`}>                                        {['Situation', 'Task', 'Action', 'Result'].map(char => (                                            <div key={char} className="flex items-center gap-2 text-[10px] text-[var(--text-secondary)] font-mono">                                                <span className="w-5 h-5 rounded flex items-center justify-center bg-cyan-500/10 text-cyan-400 border border-cyan-500/20">{char[0]}</span>                                                Type your [{char.toLowerCase()}] here...                                            </div>                                        ))}                                    </div>                                    <div className="relative flex-1 group min-h-[300px]">                                        <div className="absolute -inset-0.5 bg-gradient-to-r from-violet-500/30 to-cyan-500/30 rounded-xl blur opacity-0 group-hover:opacity-10 transition duration-500"></div>                                        <textarea                                            ref={textareaRef}                                            value={answerText}                                            onChange={(e) => setAnswerText(e.target.value)}                                            placeholder="Write your answer here or utilize the tools below..."                                            className="relative w-full h-full bg-[#0d0f1a] border border-white/10 rounded-xl p-6 text-sm text-[var(--text-primary)] leading-loose resize-none focus:outline-none focus:border-violet-500/50 shadow-inner"                                            disabled={isGenerating || isEvaluating}                                        />                                        {(isGenerating || isEvaluating) && (                                            <div className="absolute inset-x-0 bottom-0 h-1 bg-gradient-to-r from-violet-500 to-cyan-500 animate-pulse rounded-b-xl" />                                        )}                                    </div>                                </div>                                {}                                <div className="mt-6 flex flex-wrap gap-4">                                    <button onClick={handleGenerateAnswer} disabled={isGenerating || isEvaluating} className="flex-1 py-3 px-4 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-sm font-medium text-[var(--text-primary)] transition-all flex items-center justify-center gap-2 disabled:opacity-50">                                        {isGenerating ? <RefreshCw className="w-4 h-4 animate-spin text-cyan-400" /> : <PenLine className="w-4 h-4 text-cyan-400" />}                                        Generate Draft                                    </button>                                    <button onClick={handleEvaluateAnswer} disabled={!answerText.trim() || isGenerating || isEvaluating} className="flex-1 py-3 px-4 bg-violet-600 hover:bg-violet-500 text-[var(--text-primary)] rounded-xl text-sm font-medium shadow-[0_0_20px_rgba(124,58,237,0.3)] transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:shadow-none bg-gradient-to-r from-violet-600 to-fuchsia-600">                                        {isEvaluating ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />}                                        Evaluate Answer                                    </button>                                    <button onClick={() => setShowHistory(!showHistory)} className="py-3 px-4 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-sm font-medium text-[var(--text-primary)] transition-all flex items-center justify-center gap-2">                                        <History className="w-4 h-4" /> History                                    </button>                                    <button onClick={handleExportPlaybook} className="py-3 px-4 bg-cyan-500/10 hover:bg-cyan-500/20 border border-cyan-500/20 rounded-xl text-sm font-medium text-cyan-400 transition-all flex items-center justify-center gap-2">                                        <BookOpen className="w-4 h-4" /> Export PDF                                    </button>                                </div>                                {}                                <AnimatePresence>                                    {showImprovedAnswer && evalResult && (                                        <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="mt-6">                                            <div className="p-6 bg-cyan-500/5 border border-cyan-500/20 rounded-xl">                                                <h4 className="text-xs font-semibold text-cyan-400 uppercase tracking-widest mb-4 flex items-center gap-2"><Sparkles className="w-4 h-4" /> AI Improved Version</h4>                                                <p className="text-sm text-[var(--text-primary)] leading-relaxed whitespace-pre-wrap">{evalResult.improved_answer}</p>                                                <button onClick={() => setAnswerText(evalResult.improved_answer)} className="mt-4 px-4 py-2 bg-white/5 hover:bg-white/10 rounded-lg text-xs font-medium text-[var(--text-primary)] transition-colors border border-white/10">Apply to editor</button>                                            </div>                                        </motion.div>                                    )}                                </AnimatePresence>                                {}                                <AnimatePresence>                                    {showHistory && (                                        <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="mt-6 border border-white/10 rounded-xl bg-[var(--card-bg)] overflow-hidden">                                            <div className="p-4 border-b border-white/5 flex justify-between items-center bg-[#0d0f1a]">                                                <h4 className="text-sm font-medium text-[var(--text-primary)] flex items-center gap-2"><History className="w-4 h-4 text-violet-400" /> Past Attempts</h4>                                                <button onClick={() => setShowHistory(false)} className="text-[var(--text-muted)] hover:text-[var(--text-primary)]"><X className="w-4 h-4" /></button>                                            </div>                                            <div className="p-6">                                                {isLoadingHistory ? (                                                    <div className="flex justify-center py-8"><RefreshCw className="w-6 h-6 animate-spin text-violet-500" /></div>                                                ) : answerHistory.length === 0 ? (                                                    <div className="text-center text-sm text-[var(--text-muted)] py-8">No past attempts found. Evaluate an answer to save it!</div>                                                ) : (                                                    <div className="space-y-6">                                                        {}                                                        {answerHistory.length > 1 && (                                                            <div className="h-48 w-full border border-white/5 rounded-lg bg-[#0d0f1a] p-4">                                                                <h5 className="text-[10px] font-bold uppercase text-[var(--text-muted)] mb-2">Score Progression</h5>                                                                <ResponsiveContainer width="100%" height="100%">                                                                    <LineChart data={answerHistory.map((h, i) => ({ attempt: `Attempt ${i + 1}`, score: h.overall_score }))}>                                                                        <XAxis dataKey="attempt" tick={{ fill: '#64748b', fontSize: 10 }} axisLine={false} tickLine={false} />                                                                        <YAxis domain={[0, 100]} tick={{ fill: '#64748b', fontSize: 10 }} axisLine={false} tickLine={false} width={30} />                                                                        <RechartsTooltip contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', fontSize: '12px' }} />                                                                        <Line type="monotone" dataKey="score" stroke="#8b5cf6" strokeWidth={3} dot={{ fill: '#8b5cf6', strokeWidth: 2, r: 4 }} activeDot={{ r: 6 }} />                                                                    </LineChart>                                                                </ResponsiveContainer>                                                            </div>                                                        )}                                                        {}                                                        <div className="space-y-3">                                                            {answerHistory.map((h, i) => (                                                                <div key={h.id} className="p-4 rounded-lg bg-white/5 border border-white/10 hover:border-violet-500/30 transition-colors">                                                                    <div className="flex justify-between items-center mb-3">                                                                        <span className="text-xs font-bold text-violet-400 uppercase tracking-wider">Attempt {i + 1}</span>                                                                        <div className="flex items-center gap-3">                                                                            <span className="text-xs text-[var(--text-muted)]">{new Date(h.created_at).toLocaleDateString()}</span>                                                                            <span className="px-2 py-1 bg-white/10 rounded font-bold text-xs text-[var(--text-primary)]">{h.overall_score} pts</span>                                                                        </div>                                                                    </div>                                                                    <p className="text-sm text-[var(--text-primary)] leading-relaxed line-clamp-3 hover:line-clamp-none transition-all cursor-pointer">                                                                        {h.answer_text}                                                                    </p>                                                                    <button onClick={() => { setAnswerText(h.answer_text); setShowHistory(false); toast.success("Draft loaded from history."); }} className="mt-3 text-[10px] uppercase font-bold text-cyan-400 hover:text-cyan-300 flex items-center gap-1">                                                                        <RefreshCw className="w-3 h-3" /> Load into Editor                                                                    </button>                                                                </div>                                                            ))}                                                        </div>                                                    </div>                                                )}                                            </div>                                        </motion.div>                                    )}                                </AnimatePresence>                            </div>                        </>                    ) : (                        <div className="flex-1 flex flex-col items-center justify-center text-[var(--text-muted)]">                            <Focus className="w-16 h-16 mb-4 opacity-20" />                            <p>Select a question from the bank to start practicing</p>                        </div>                    )}                </div>                {}                <aside className="w-[320px] flex-shrink-0 border-l border-[var(--card-border)] bg-[#0A0D14] flex flex-col overflow-y-auto custom-scrollbar">                    <div className="p-6">                        <div className="flex items-center gap-3 mb-8">                            <span className="relative flex h-3 w-3">                                <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${evalResult ? 'bg-cyan-400' : 'bg-slate-600'}`}></span>                                <span className={`relative inline-flex rounded-full h-3 w-3 ${evalResult ? 'bg-cyan-500' : 'bg-slate-500'}`}></span>                            </span>                            <h2 className="text-lg font-bold text-[var(--text-primary)] tracking-wide">AI Coach</h2>                        </div>                        {}                        <div className="h-48 w-full mb-8 relative">                            {!evalResult && (                                <div className="absolute inset-0 flex items-center justify-center z-10 text-xs text-[var(--text-muted)]">                                    Evaluate answer to see score                                </div>                            )}                            <ResponsiveContainer width="100%" height="100%">                                <RadarChart cx="50%" cy="50%" outerRadius="70%" data={radarData} className={!evalResult ? 'opacity-20' : ''}>                                    <PolarGrid stroke="rgba(255,255,255,0.1)" />                                    <PolarAngleAxis dataKey="subject" tick={{ fill: '#94a3b8', fontSize: 10 }} />                                    <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />                                    <Radar name="Score" dataKey="A" stroke="#06b6d4" fill="#06b6d4" fillOpacity={0.3} dot={false} isAnimationActive={true} />                                </RadarChart>                            </ResponsiveContainer>                        </div>                        {evalResult ? (                            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-8">                                {}                                <div className="text-center">                                    <span className="text-4xl font-bold text-[var(--text-primary)]">{evalResult.overall_score}</span>                                    <span className="text-[var(--text-muted)] ml-1">/ 100</span>                                </div>                                {}                                <div>                                    <h4 className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest mb-3">STAR Protocol</h4>                                    <div className="flex gap-2">                                        {[                                            { id: 'situation', label: 'S' },                                            { id: 'task', label: 'T' },                                            { id: 'action', label: 'A' },                                            { id: 'result', label: 'R' }                                        ].map(item => {                                            const active = evalResult.star_detected[item.id as keyof typeof evalResult.star_detected];                                            return (                                                <div key={item.id} className={`flex-1 aspect-square rounded-lg flex items-center justify-center text-lg font-bold transition-colors ${active ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 shadow-[0_0_10px_rgba(16,185,129,0.1)]' : 'bg-white/5 text-slate-600 border border-white/5'}`}>                                                    {item.label}                                                </div>                                            );                                        })}                                    </div>                                </div>                                {}                                <div>                                    <h4 className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest mb-3">Tone Check</h4>                                    <div className="relative h-2 w-full bg-gradient-to-r from-red-500/50 via-yellow-500/50 to-emerald-500/50 rounded-full">                                        <div className="absolute top-1/2 -translate-y-1/2 w-4 h-4 bg-white rounded-full shadow-lg transition-all duration-700"                                            style={{ left: evalResult.tone === 'passive' ? '10%' : evalResult.tone === 'neutral' ? '50%' : '90%', transform: 'translate(-50%, -50%)' }} />                                    </div>                                    <div className="flex justify-between text-[10px] text-[var(--text-muted)] mt-2 font-medium">                                        <span>Passive</span>                                        <span className="text-emerald-400">Confident</span>                                    </div>                                </div>                                {}                                {evalResult.hedging_words_found.length > 0 && (                                    <div>                                        <h4 className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest mb-3 flex items-center gap-1"><AlertCircle className="w-3 h-3 text-red-400" /> Weak Phrasing Detected</h4>                                        <div className="flex flex-wrap gap-1.5">                                            {evalResult.hedging_words_found.map(word => (                                                <span key={word} className="px-2 py-0.5 rounded bg-red-500/20 text-red-400 text-[10px] border border-red-500/30 font-medium">"{word}"</span>                                            ))}                                        </div>                                    </div>                                )}                                {}                                <div>                                    <h4 className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-widest mb-3">AI Coaching Details</h4>                                    <ul className="space-y-3">                                        {evalResult.improvement_tips.map((tip, i) => (                                            <li key={i} className="text-xs text-[var(--text-primary)] flex items-start gap-2 bg-white/5 p-3 rounded-lg border border-white/5">                                                <span className="text-cyan-400 mt-0.5">•</span> {tip}                                            </li>                                        ))}                                    </ul>                                </div>                                <button onClick={() => setShowImprovedAnswer(!showImprovedAnswer)} className="w-full py-2.5 bg-cyan-500/10 hover:bg-cyan-500/20 border border-cyan-500/30 text-cyan-400 text-xs font-semibold rounded-lg transition-colors flex items-center justify-center gap-2">                                    <PenLine className="w-3 h-3" /> {showImprovedAnswer ? 'Hide Improved Version' : 'Show Improved Version'}                                </button>                            </motion.div>                        ) : (                            <div className="space-y-6 opacity-30 pointer-events-none filter grayscale">                                <div className="h-12 bg-white/10 rounded-xl" />                                <div className="h-20 bg-white/10 rounded-xl" />                                <div className="h-32 bg-white/10 rounded-xl" />                            </div>                        )}                    </div>                </aside>            </main>        </div>    );}